/**
 * Get visible row indices from a tbody mock.
 * A row is visible when style.display !== 'none'.
 * @param {Array<{dataset: {index: string}, style: {display: string}}>} rows
 * @returns {number[]} Array of integer indices of visible rows
 */
export function getVisibleRowIndices(rows) {
  const visible = [];
  for (const row of rows) {
    if (row.style.display !== 'none') {
      visible.push(parseInt(row.dataset.index, 10));
    }
  }
  return visible;
}

/**
 * Pick a random index from an array of visible indices.
 * Returns -1 if the array is empty.
 * @param {number[]} visibleIndices
 * @param {function(): number} [randFn] - optional RNG returning [0,1); defaults to Math.random
 * @returns {number} Selected index, or -1 if no visible rows
 */
export function pickRandomIndex(visibleIndices, randFn = Math.random) {
  if (!visibleIndices || visibleIndices.length === 0) {
    return -1;
  }
  const pos = Math.floor(randFn() * visibleIndices.length);
  return visibleIndices[pos];
}

/**
 * Determine whether the random button should be enabled.
 * @param {number} visibleCount - Number of currently visible rows
 * @returns {boolean} true if button should be enabled
 */
export function shouldEnableRandomBtn(visibleCount) {
  return visibleCount > 0;
}

/**
 * Apply highlight class to a row, removing it from all others.
 * Returns an object describing what changed (for testing without real DOM).
 * @param {Array<{dataset: {index: string}, classList: {add: function, remove: function}}>} rows
 * @param {number} selectedIndex - The row index to highlight
 * @returns {{ highlighted: number|null, cleared: number[] }}
 */
export function applyHighlight(rows, selectedIndex) {
  const cleared = [];
  let highlighted = null;

  for (const row of rows) {
    const idx = parseInt(row.dataset.index, 10);
    if (idx === selectedIndex) {
      row.classList.add('random-highlight');
      highlighted = idx;
    } else {
      row.classList.remove('random-highlight');
      cleared.push(idx);
    }
  }

  return { highlighted, cleared };
}

/**
 * Full pickRandomProblem logic, operating on abstract row objects.
 * This is the pure-logic equivalent of the DOM function pickRandomProblem(fileKey).
 *
 * @param {Array<{dataset: {index: string}, style: {display: string}, classList: {add: function, remove: function}, scrollIntoView?: function}>} rows
 * @param {function(): number} [randFn] - optional RNG
 * @returns {{ selectedIndex: number, visibleCount: number }}
 *   selectedIndex: the chosen row index, or -1 if nothing visible
 *   visibleCount: how many rows were visible at time of pick
 */
export function pickRandomProblemLogic(rows, randFn = Math.random) {
  const visibleIndices = getVisibleRowIndices(rows);
  const selectedIndex = pickRandomIndex(visibleIndices, randFn);

  if (selectedIndex !== -1) {
    applyHighlight(rows, selectedIndex);
    const row = rows.find(r => parseInt(r.dataset.index, 10) === selectedIndex);
    if (row && typeof row.scrollIntoView === 'function') {
      row.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }

  return { selectedIndex, visibleCount: visibleIndices.length };
}
